              >
                {link.name}
              </a>
            ))}
            <a
              href="tel:8866757616"
              className="flex items-center space-x-2 text-brand-gold font-bold"
            >
              <Phone size={18} />
              <span>8866757616</span>
            </a>
          </motion.div>
        )}
      </AnimatePresence>
    </header>
  );
};

const AnimatePresence = ({ children }: { children: React.ReactNode }) => (
  <>{children}</>
); // Simple wrapper as Framer Motion's AnimatePresence works automatically inside motion components

export default Header;

