              <span className="text-sm">R.E</span>
            </div>
          </div>
          <div className="flex flex-col">
            <span className={`text-2xl font-serif tracking-tight leading-none ${scrolled ? 'text-brand-navy' : 'text-white'}`}>
              RUDRAY <span className="text-brand-gold">EXIM</span>
            </span>
            <span className={`text-[8px] tracking-[0.4em] uppercase font-bold ${scrolled ? 'text-brand-navy/60' : 'text-white/60'}`}>
              Global Vegetable Trade
            </span>
          </div>
        </motion.div>

        {/* Desktop Nav */}
        <nav className="hidden lg:flex items-center space-x-10">
          {navLinks.map((link) => (
            <motion.a
              key={link.name}
              href={`#${link.id}`}
              onClick={(e) => scrollToSection(e, link.id)}
              whileHover={{ y: -2 }}
              className={`text-xs font-bold tracking-widest uppercase transition-colors relative group ${
                scrolled ? 'text-brand-navy' : 'text-white'
              }`}
            >
              {link.name}
              <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-brand-gold transition-all group-hover:w-full"></span>
            </motion.a>
          ))}
          <motion.a
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            href="#contact"
            onClick={(e) => scrollToSection(e, 'contact')}
            className="px-6 py-3 rounded-full bg-brand-navy text-white text-[10px] font-black tracking-widest uppercase hover:shadow-[0_0_20px_rgba(197,160,89,0.3)] border border-brand-gold/30 transition-all"
          >
            Inquire Now
          </motion.a>
        </nav>

        {/* Mobile Menu Toggle */}
        <motion.button
          whileTap={{ scale: 0.9 }}
          className={`lg:hidden p-2 rounded-full ${scrolled ? 'text-brand-navy bg-brand-slate' : 'text-white bg-white/10'}`}
          onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
        >
          {mobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
        </motion.button>
      </div>

      {/* Mobile Menu */}
      <AnimatePresence>
        {mobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            className="absolute top-full left-0 right-0 bg-white shadow-2xl overflow-hidden lg:hidden border-t border-gray-100"
          >
            <div className="p-8 flex flex-col space-y-6">
              {navLinks.map((link, i) => (
                <motion.a
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: i * 0.1 }}
                  key={link.name}
                  href={`#${link.id}`}
                  className="text-xl font-serif text-brand-navy flex justify-between items-center group"
                  onClick={(e) => scrollToSection(e, link.id)}
                >
                  <span>{link.name}</span>
                  <div className="w-8 h-[1px] bg-brand-gold scale-x-0 group-hover:scale-x-100 transition-transform origin-right" />
                </motion.a>
              ))}
              <div className="pt-6 border-t border-gray-100 flex flex-col space-y-4">
                <a href="tel:8866757616" className="flex items-center space-x-3 text-brand-gold font-bold">
